// Cache Sync Manager - Real-time cache invalidation & sync
// Mengelola sinkronisasi cache localStorage dengan Firebase real-time updates

const CacheSyncManager = {
  listeners: {},
  syncTimers: {},
  
  // Initialize real-time listeners untuk cache invalidation
  init() {
    if (!db || !db.ref) return console.warn("[CacheSyncManager] DB not ready");
    
    // Listen untuk perubahan status ujian (hasil baru, remedial, dll)
    if (State.user && State.user.id) {
      this.listenToUserResults(State.user.id);
    }
    
    // Listen untuk perubahan jadwal (jika ada update dari admin)
    this.listenToScheduleChanges();
    
    console.log("[CacheSyncManager] ✅ Initialized");
  },
  
  // Listen ke hasil ujian user untuk invalidate cache
  listenToUserResults(userId) {
    try {
      const ref = db.ref("/hasil").orderByChild("userId").equalTo(userId);
      
      if (this.listeners.userResults) {
        this.listeners.userResults.off();
      }
      
      this.listeners.userResults = ref.on("value", (snapshot) => {
        const results = snapshot.val() || {};
        console.log("[CacheSyncManager] User results updated:", Object.keys(results).length, "items");
        
        // Invalidate cache untuk ujian yang sudah selesai
        for (let key in results) {
          const result = results[key];
          if (result.examId && result.userId === userId) {
            this.invalidateExamCache(result.examId, userId);
            this.updateScheduleStatus(result.examId, "SELESAI");
          }
        }
        
        // Refresh UI jika ada perubahan
        if (typeof renderMobileSchedule === "function") {
          renderMobileSchedule();
        }
      });
    } catch (e) {
      console.warn("[CacheSyncManager] Error listening to results:", e);
    }
  },
  
  // Listen ke perubahan jadwal
  listenToScheduleChanges() {
    try {
      if (this.listeners.schedules) {
        this.listeners.schedules.off();
      }
      
      this.listeners.schedules = db.ref("/jadwal").on("value", (snapshot) => {
        const jadwal = snapshot.val() || {};
        console.log("[CacheSyncManager] Jadwal updated:", Object.keys(jadwal).length, "items");
        
        // Update cache jadwal
        try {
          localStorage.setItem("CBT_CACHE_JADWAL", JSON.stringify(jadwal));
          localStorage.setItem("CBT_CACHE_JADWAL_TIME", Date.now().toString());
          
          // Update user-specific cache jika ada
          if (State.user && State.user.id) {
            localStorage.setItem(`CBT_CACHE_JADWAL_${State.user.id}`, JSON.stringify(jadwal));
            localStorage.setItem(`CBT_CACHE_JADWAL_TIME_${State.user.id}`, Date.now().toString());
          }
        } catch (e) {
          console.warn("[CacheSyncManager] Failed to update jadwal cache:", e);
        }
        
        // Refresh UI
        if (typeof renderMobileSchedule === "function") {
          renderMobileSchedule();
        }
      });
    } catch (e) {
      console.warn("[CacheSyncManager] Error listening to schedules:", e);
    }
  },
  
  // Invalidate cache untuk ujian tertentu
  invalidateExamCache(examId, userId) {
    try {
      // Hapus cache jadwal user-specific
      if (userId) {
        localStorage.removeItem(`CBT_CACHE_JADWAL_${userId}`);
        localStorage.removeItem(`CBT_CACHE_JADWAL_TIME_${userId}`);
      }
      
      // Hapus cache soal
      const versions = ["v0", "v1", "v2", "v3", "v4", "v5"];
      versions.forEach(v => {
        localStorage.removeItem(`SOAL_${examId}_${v}`);
        localStorage.removeItem(`SOAL_${examId}_${v}_date`);
      });
      
      // Hapus cache token
      localStorage.removeItem(`CBT_TOKEN_HASH_${examId}`);
      
      console.log(`[CacheSyncManager] ✅ Invalidated cache for exam ${examId}`);
    } catch (e) {
      console.warn("[CacheSyncManager] Error invalidating cache:", e);
    }
  },
  
  // Update status ujian di cache jadwal
  updateScheduleStatus(examId, status) {
    try {
      const jadwal = JSON.parse(localStorage.getItem("CBT_CACHE_JADWAL") || "{}");
      if (jadwal[examId]) {
        jadwal[examId]._cachedStatus = status;
        localStorage.setItem("CBT_CACHE_JADWAL", JSON.stringify(jadwal));
      }
    } catch (e) {
      console.warn("[CacheSyncManager] Error updating schedule status:", e);
    }
  },
  
  // Clear cache saat remedial dilakukan
  clearCacheForRemedial(examId, userId) {
    console.log(`[CacheSyncManager] Clearing cache for remedial: exam=${examId}, user=${userId}`);
    
    // Invalidate semua cache untuk ujian ini
    this.invalidateExamCache(examId, userId);
    
    // Hapus flag "sudah dikerjakan"
    if (userId) {
      localStorage.removeItem(`CBT_SUBMITTED_${examId}_${userId}`);
    }
    
    // Refresh UI
    if (typeof renderMobileSchedule === "function") {
      renderMobileSchedule();
    }
  },
  
  // Refresh cache jadwal dari Firebase
  async refreshScheduleCache(force = false) {
    try {
      const now = Date.now();
      const lastSync = parseInt(localStorage.getItem("CBT_CACHE_JADWAL_TIME") || "0");
      
      // Skip jika baru saja di-sync (< 30 detik)
      if (!force && now - lastSync < 30000) {
        console.log("[CacheSyncManager] Cache masih fresh, skip refresh");
        return;
      }
      
      console.log("[CacheSyncManager] Refreshing schedule cache from Firebase...");
      
      if (typeof dbConnectFast === "function") {
        await dbConnectFast();
      }
      
      const snapshot = await db.ref("/jadwal").once("value");
      const jadwal = snapshot.val() || {};
      
      localStorage.setItem("CBT_CACHE_JADWAL", JSON.stringify(jadwal));
      localStorage.setItem("CBT_CACHE_JADWAL_TIME", now.toString());
      
      if (State.user && State.user.id) {
        localStorage.setItem(`CBT_CACHE_JADWAL_${State.user.id}`, JSON.stringify(jadwal));
        localStorage.setItem(`CBT_CACHE_JADWAL_TIME_${State.user.id}`, now.toString());
      }
      
      console.log("[CacheSyncManager] ✅ Schedule cache refreshed");
      
      if (typeof dbDisconnect === "function") {
        dbDisconnect();
      }
      
      return jadwal;
    } catch (e) {
      console.warn("[CacheSyncManager] Error refreshing cache:", e);
      return null;
    }
  },
  
  // Cleanup listeners
  destroy() {
    for (let key in this.listeners) {
      if (this.listeners[key] && typeof this.listeners[key].off === "function") {
        this.listeners[key].off();
      }
    }
    
    for (let key in this.syncTimers) {
      clearInterval(this.syncTimers[key]);
    }
    
    this.listeners = {};
    this.syncTimers = {};
    console.log("[CacheSyncManager] ✅ Destroyed");
  }
};

// Export untuk global access
window.CacheSyncManager = CacheSyncManager;
